mapper.select:
SELECT order_num, work_order_id, plan_id, item_name, type, order_qty, ename, order_start, work_status, total_count FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT wo.order_num, wo.order_id AS work_order_id, pp.plan_id, i.name AS item_name, wo.order_qty AS order_qty, e.ename, wo.order_start, wo.order_status AS work_status, i.type, f.facility_name, COUNT(*) OVER() AS total_count FROM work_order wo LEFT JOIN emp e ON wo.emp_num = e.emp_num LEFT JOIN production_plan pp ON wo.plan_num = pp.plan_num LEFT JOIN item i ON pp.item_num = i.item_num LEFT JOIN ( SELECT item_num, facility_num FROM ( SELECT item_num, facility_num, ROW_NUMBER() OVER (PARTITION BY item_num ORDER BY flow) AS rn FROM process WHERE facility_num IS NOT NULL ) WHERE rn = 1 ) pr ON i.item_num = pr.item_num LEFT JOIN facility f ON pr.facility_num = f.facility_num
AND wo.order_start >= TO_DATE(#{startDate}, 'YYYY-MM-DD')
AND wo.order_start <= TO_DATE(#{endDate}, 'YYYY-MM-DD')
AND wo.order_status = #{work_status}
AND i.type = #{item_type}
AND pp.item_num = #{item_num}
AND (wo.order_id LIKE '%' || #{keyword} || '%' OR i.name LIKE '%' || #{keyword} || '%')
ORDER BY wo.order_num DESC ) inner_q WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

mapper.insert:

    SELECT pp.plan_id || '-' || (
        SELECT NVL(MAX(
            CASE WHEN REGEXP_LIKE(wo.order_id, pp.plan_id || '-[0-9]+')
                 THEN TO_NUMBER(SUBSTR(wo.order_id, LENGTH(pp.plan_id)+2))
                 ELSE 0 END
        ), 0) + 1
        FROM work_order wo
        WHERE wo.plan_num = #{plan_num}
    )
    FROM production_plan pp
    WHERE pp.plan_num = #{plan_num}

INSERT INTO work_order
    (order_num, order_id, order_qty, order_status, emp_num,
     plan_num, current_qty, content, created_at, order_start, order_end)
SELECT WO_SEQ.NEXTVAL, #{work_order_id}, #{order_qty}, '대기', #{emp_num},
       #{plan_num}, 0, #{content}, SYSDATE, #{order_start}, #{order_end}
FROM DUAL
WHERE NOT EXISTS (
    SELECT 1 FROM production_plan
    WHERE plan_num = #{plan_num}
      AND (plan_status = '취소' OR SYSDATE > plan_end)
)

mapper.update:
UPDATE work_order
SET order_status = #{work_status}
WHERE order_id = #{work_order_id}
  AND order_status NOT IN ('완료', '취소')
